{
  "schema_name": "eywa_node_response",
  "schema_version": "v1",
  "orchestration_decision": "delegate",
  "decision_notes": "The problem is a search and optimization task involving spatial pattern matching under uncertainty. I will split this into a geometric pattern matching subproblem and a search strategy optimization subproblem.",
  "helpers": [
    {
      "label": "pattern_matcher",
      "instructions": "Given a set of polyomino shapes and a grid containing noisy aggregate query results (counts of oil cells in specific regions), develop an algorithm to identify all possible valid placements of the polyominoes that are consistent with the observed aggregate data. Account for the fact that queries are noisy."
    },
    {
      "label": "cost_optimizer",
      "instructions": "Given a set of potential polyomino placements and the costs associated with different types of actions (drilling specific cells vs. performing aggregate queries), design an optimal decision tree or sequential sampling strategy that minimizes the total expected cost to confirm the exact location of all oil-containing cells."
    }
  ],
  "synthesis_brief": "The parent will use the pattern_matcher output to define the search space of candidate oil-field configurations. It will then apply the cost_optimizer's strategy to select the sequence of probes (drilling and queries) that most efficiently narrows down the candidates to a single certain configuration, ultimately outputting the final cell coordinates."
}

